import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../api';
import { BottomNav } from './Home';

export default function Profile() {
  const { id } = useParams(); // if undefined, show own profile
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);

  const profileId = id || user?.id;

  useEffect(() => {
    if (!profileId) { navigate('/signin'); return; }
    api.get(`/users/${profileId}`)
      .then(res => setProfile(res.data))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, [profileId]);

  const isOwnProfile = !id || parseInt(id) === user?.id;

  if (loading) return (
    <div className="app-container">
      <div className="loading"><div className="spinner" /></div>
    </div>
  );

  return (
    <div className="app-container">
      <div className="page-header">
        {id && <button className="back-btn" onClick={() => navigate(-1)}>← Назад</button>}
        <span className="page-title">Profile</span>
        {isOwnProfile && (
          <button
            onClick={() => { logout(); navigate('/signin'); }}
            style={{ background: 'none', border: 'none', color: '#dc2626', fontWeight: 600, fontSize: 14 }}
          >
            Выйти
          </button>
        )}
      </div>

      <div style={{ padding: '24px 20px 100px' }}>
        {/* Avatar & name */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 16, marginBottom: 24 }}>
          <div style={{
            width: 72, height: 72, borderRadius: '50%',
            background: 'linear-gradient(135deg, var(--green), var(--green-light))',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontSize: 28, fontWeight: 800, color: 'white',
            boxShadow: '0 4px 16px rgba(58,125,44,0.3)'
          }}>
            {profile?.username?.[0]?.toUpperCase() || '?'}
          </div>
          <div>
            <div style={{ fontSize: 22, fontWeight: 800 }}>{profile?.username}</div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginTop: 4 }}>
              <span style={{ fontSize: 18 }}>⭐</span>
              <span style={{ fontWeight: 700, fontSize: 18 }}>{profile?.rating || '0.0'}</span>
              <span style={{ color: 'var(--text-muted)', fontSize: 14 }}>
                ({profile?.rating_count || 0} отзывов)
              </span>
            </div>
          </div>
        </div>

        {/* Stats */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12, marginBottom: 24 }}>
          <div className="card" style={{ textAlign: 'center' }}>
            <div style={{ fontSize: 28, fontWeight: 800, color: 'var(--green)' }}>
              {profile?.completed_tasks || 0}
            </div>
            <div style={{ fontSize: 13, color: 'var(--text-muted)', marginTop: 4, fontWeight: 600 }}>
              Completed Tasks
            </div>
          </div>
          <div className="card" style={{ textAlign: 'center' }}>
            <div style={{ fontSize: 28, fontWeight: 800, color: 'var(--green)' }}>
              {profile?.rating || '—'}
            </div>
            <div style={{ fontSize: 13, color: 'var(--text-muted)', marginTop: 4, fontWeight: 600 }}>
              Avg Rating
            </div>
          </div>
        </div>

        {/* Own profile actions */}
        {isOwnProfile && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10, marginBottom: 24 }}>
            <button className="btn-primary" onClick={() => navigate('/create-task')}>
              ➕ Создать задачу
            </button>
            <button className="btn-secondary" onClick={() => navigate('/my-tasks')}>
              📋 Мои задачи
            </button>
            {user?.role === 'admin' && (
              <button
                onClick={() => navigate('/admin')}
                style={{
                  background: '#fef3c7', color: '#d97706', border: 'none',
                  padding: 14, borderRadius: 14, fontWeight: 700, fontSize: 16
                }}
              >
                🛡️ Admin Panel
              </button>
            )}
          </div>
        )}

        {/* Comments */}
        {profile?.comments?.length > 0 && (
          <div>
            <h3 style={{ fontWeight: 700, fontSize: 16, marginBottom: 12 }}>Comments</h3>
            {profile.comments.map((c, i) => (
              <div key={i} className="card" style={{ marginBottom: 10 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6 }}>
                  <span style={{ fontWeight: 600, fontSize: 14 }}>{c.rater_name}</span>
                  <span style={{ color: 'var(--text-muted)', fontSize: 12 }}>
                    {'⭐'.repeat(c.score)}
                  </span>
                </div>
                <p style={{ fontSize: 14, color: 'var(--text-muted)', lineHeight: 1.5 }}>{c.comment}</p>
              </div>
            ))}
          </div>
        )}

        {(!profile?.comments || profile.comments.length === 0) && (
          <div style={{ textAlign: 'center', color: 'var(--text-muted)', fontSize: 14, padding: '20px 0' }}>
            Отзывов пока нет
          </div>
        )}
      </div>

      {isOwnProfile && <BottomNav />}
    </div>
  );
}
